-- Talk2Me CRM v3.1.0 -- Fixed accounts, fixed services and unified CRM relationships.
-- Import this file into the uent_talk2me_crm database only.

CREATE TABLE IF NOT EXISTS fixed_accounts (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
  account_number VARCHAR(80) NOT NULL,
  account_number_normalised VARCHAR(80) NOT NULL,
  customer_name VARCHAR(180) NOT NULL,
  contact_name VARCHAR(160) NULL,
  contact_number VARCHAR(30) NULL,
  contact_number_normalised VARCHAR(20) NULL,
  email VARCHAR(190) NULL,
  authorised_contact_name VARCHAR(160) NULL,
  authorised_contact_number VARCHAR(30) NULL,
  authority_status ENUM('unknown','confirmed','not_authorised') NOT NULL DEFAULT 'unknown',
  linked_mobile_account_number VARCHAR(80) NULL,
  linked_client_id BIGINT UNSIGNED NULL,
  assigned_staff_id BIGINT UNSIGNED NULL,
  account_status ENUM('active','inactive','cancelled','unknown') NOT NULL DEFAULT 'active',
  notes TEXT NULL,
  source_system VARCHAR(80) NOT NULL DEFAULT 'Fixed Base spreadsheet',
  raw_import_json LONGTEXT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uq_fixed_accounts_number (account_number_normalised),
  KEY idx_fixed_accounts_contact (contact_number_normalised),
  KEY idx_fixed_accounts_email (email),
  KEY idx_fixed_accounts_staff (assigned_staff_id),
  KEY idx_fixed_accounts_mobile_account (linked_mobile_account_number),
  CONSTRAINT fk_fixed_accounts_client FOREIGN KEY (linked_client_id) REFERENCES clients(id) ON DELETE SET NULL,
  CONSTRAINT fk_fixed_accounts_staff FOREIGN KEY (assigned_staff_id) REFERENCES staff_users(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS fixed_services (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
  fixed_account_id BIGINT UNSIGNED NOT NULL,
  service_title VARCHAR(180) NULL,
  branch_name VARCHAR(180) NULL,
  order_number VARCHAR(80) NULL,
  router_model VARCHAR(120) NULL,
  mac_address VARCHAR(40) NULL,
  mac_address_normalised VARCHAR(20) NULL,
  solution_id VARCHAR(80) NULL,
  sim_number VARCHAR(30) NULL,
  package_name VARCHAR(180) NULL,
  package_name_normalised VARCHAR(180) NULL,
  activation_date DATE NULL,
  service_status ENUM('active','pending','suspended','cancelled','unknown') NOT NULL DEFAULT 'active',
  cancellation_date DATE NULL,
  installation_address VARCHAR(255) NULL,
  technical_notes TEXT NULL,
  data_quality_notes VARCHAR(255) NULL,
  source_row_hash CHAR(64) NOT NULL,
  source_system VARCHAR(80) NOT NULL DEFAULT 'Fixed Base spreadsheet',
  raw_import_json LONGTEXT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uq_fixed_services_hash (source_row_hash),
  UNIQUE KEY uq_fixed_services_order (order_number),
  UNIQUE KEY uq_fixed_services_solution (solution_id),
  KEY idx_fixed_services_account (fixed_account_id),
  KEY idx_fixed_services_sim (sim_number),
  KEY idx_fixed_services_mac (mac_address_normalised),
  KEY idx_fixed_services_activation (activation_date),
  KEY idx_fixed_services_status (service_status),
  CONSTRAINT fk_fixed_services_account FOREIGN KEY (fixed_account_id) REFERENCES fixed_accounts(id) ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

ALTER TABLE inquiries
  ADD COLUMN IF NOT EXISTS service_type ENUM('mobile','fixed','general') NOT NULL DEFAULT 'mobile' AFTER client_id,
  ADD COLUMN IF NOT EXISTS fixed_account_id BIGINT UNSIGNED NULL AFTER service_type,
  ADD COLUMN IF NOT EXISTS fixed_service_id BIGINT UNSIGNED NULL AFTER fixed_account_id;

ALTER TABLE staff_tasks
  ADD COLUMN IF NOT EXISTS related_fixed_account_id BIGINT UNSIGNED NULL AFTER related_client_id,
  ADD COLUMN IF NOT EXISTS related_fixed_service_id BIGINT UNSIGNED NULL AFTER related_fixed_account_id;

CREATE INDEX IF NOT EXISTS idx_inquiries_fixed_account ON inquiries (fixed_account_id, status, created_at);
CREATE INDEX IF NOT EXISTS idx_inquiries_fixed_service ON inquiries (fixed_service_id, status, created_at);
CREATE INDEX IF NOT EXISTS idx_tasks_fixed_account ON staff_tasks (related_fixed_account_id, status, created_at);
CREATE INDEX IF NOT EXISTS idx_tasks_fixed_service ON staff_tasks (related_fixed_service_id, status, created_at);

